sys_script_include.script:
function CleanupATF()
{
	if (IsTestRunning() == true)
	{
		Log('An ATF test is currently running. The test must be stopped before the full cleanup can take place!');
		return false;
	}

	var grRollbackContexts = new GlideRecord('sys_rollback_context');
	grRollbackContexts.addQuery('type','=','test_execution');
	//grRollbackContexts.addQuery('state','=','in_progress');
	grRollbackContexts.setLimit(100);
	grRollbackContexts.query();
	while (grRollbackContexts.next() == true)
	{
		// GlideRecordDelete(grRollbackContexts);
		var grRollbackSequence = new GlideRecord('sys_rollback_sequence');
		grRollbackSequence.addQuery('context','=',grRollbackContext.sys_id);
		grRollbackSequence.query();
		Log(RenderRecordSummary(grRollbackContexts) + ' (' + grRollbackSequence.getRowCount() + ')');

		while (grRollbackSequence.next() == true)
		{

			// GlideRecordDelete(grRollbackSequence);
		}

	}

	Log('Cleanup of ATF result records has been completed.');
	return true;
}
